from flask import Flask, render_template, request, redirect, url_for, session, jsonify
from functools import wraps
import csv, os, base64 as _b64, re as _re

# ── Admin Users ───────────────────────────────────────────
ADMIN_USERS = {
    "admin":      {"password": "admin123",  "name": "System Admin",     "role": "Super Admin"},
    "doctor":     {"password": "doctor456", "name": "Dr. Katlo Sefawe", "role": "Medical Officer"},
    "pharmacist": {"password": "pharma789", "name": "Thabo Sithole",    "role": "Pharmacist"},
}

# ── Paths ─────────────────────────────────────────────────
BASE     = os.path.dirname(os.path.abspath(__file__))
TMPL_DIR = os.path.join(BASE, 'templates')
os.makedirs(TMPL_DIR, exist_ok=True)

# ── CSV loader ────────────────────────────────────────────
def load_csv(filename):
    for folder in [BASE, os.path.join(BASE, 'data')]:
        p = os.path.join(folder, filename)
        if os.path.exists(p):
            with open(p, newline='', encoding='utf-8') as f:
                return list(csv.DictReader(f))
    raise FileNotFoundError(f"\n❌ '{filename}' not found.\nCopy all CSV files into: {BASE}\n")

# ── Load data ─────────────────────────────────────────────
facilities_raw    = load_csv("facilities.csv")
medicines_raw     = load_csv("medicines.csv")
snapshot_raw      = load_csv("inventory_snapshot.csv")
expiry_raw        = load_csv("expiry_summary.csv")
stockout_raw      = load_csv("stockout_risk.csv")
redist_raw        = load_csv("redistribution_recommendations.csv")
district_risk_raw = load_csv("district_risk.csv")
disease_raw       = load_csv("disease_cases.csv")
symptom_raw       = load_csv("symptom_reports.csv")

# ── Lookups ───────────────────────────────────────────────
med_lookup = {m["medicine_id"]: m for m in medicines_raw}
fac_lookup = {f["facility_id"]: f for f in facilities_raw}
fac_dist   = {f["facility_id"]: f["district"] for f in facilities_raw}
snapshot   = snapshot_raw
stockout_7d  = [r for r in stockout_raw if r["horizon_days"] == "7"]
stockout_30d = [r for r in stockout_raw if r["horizon_days"] == "30"]

# Latest district risk
latest_risk = {}
for r in district_risk_raw:
    k = (r["district"], r["disease"])
    if k not in latest_risk or r["week_start_date"] > latest_risk[k]["week_start_date"]:
        latest_risk[k] = r
district_risks = list(latest_risk.values())

# Latest disease cases
latest_cases = {}
for r in disease_raw:
    k = (r["district"], r["disease"])
    if k not in latest_cases or r["week_start_date"] > latest_cases[k]["week_start_date"]:
        latest_cases[k] = r
disease_cases = list(latest_cases.values())

# Latest symptoms
latest_sym = {}
for r in symptom_raw:
    k = r["district"]
    if k not in latest_sym or r["week_start_date"] > latest_sym[k]["week_start_date"]:
        latest_sym[k] = r
symptoms = list(latest_sym.values())

# ── Dashboard stats ───────────────────────────────────────
total_stock    = sum(int(float(r["quantity_on_hand"])) for r in snapshot)
out_of_stock   = sum(1 for r in snapshot if r["stock_status"] == "Out")
low_stock      = sum(1 for r in snapshot if r["stock_status"] == "Low")
critical_alerts= out_of_stock + sum(1 for r in expiry_raw if r["expiry_risk_level"] == "High")
predicted_short= sum(1 for r in stockout_30d if r["stockout_risk_level"] == "High")

stats = {
    "total_stock":         total_stock,
    "active_facilities":   len(facilities_raw),
    "critical_alerts":     critical_alerts,
    "predicted_shortages": predicted_short,
    "out_of_stock":        out_of_stock,
    "low_stock":           low_stock,
    "redist_count":        len(redist_raw),
    "high_risk_districts": sum(1 for r in district_risks if r["risk_level"] == "High"),
}

# ── AI Alerts ─────────────────────────────────────────────
alerts = []
for r in snapshot:
    if r["stock_status"] == "Out":
        fac = fac_lookup.get(r["facility_id"], {})
        med = med_lookup.get(r["medicine_id"], {})
        alerts.append({"type":"critical",
            "med": med.get("medicine_name", r["medicine_id"]),
            "msg": f"STOCK OUT at {fac.get('facility_name','?')} ({fac.get('district','?')}). Immediate resupply required."})
for r in expiry_raw:
    if r["expiry_risk_level"] == "High":
        fac = fac_lookup.get(r["facility_id"], {})
        med = med_lookup.get(r["medicine_id"], {})
        alerts.append({"type":"expiry",
            "med": med.get("medicine_name", r["medicine_id"]),
            "msg": f"{r['qty_expiring_30d']} units expiring within 30 days at {fac.get('facility_name','?')}. Redistribute urgently."})
seen = set()
for r in stockout_7d:
    if r["stockout_risk_level"] == "High":
        key = (r["facility_id"], r["medicine_id"])
        if key not in seen:
            seen.add(key)
            fac = fac_lookup.get(r["facility_id"], {})
            med = med_lookup.get(r["medicine_id"], {})
            alerts.append({"type":"shortage",
                "med": med.get("medicine_name", r["medicine_id"]),
                "msg": f"High stockout risk within 7 days at {fac.get('facility_name','?')} ({fac.get('district','?')}). Probability: {float(r['stockout_probability']):.0%}"})

# ── Patient portal data ───────────────────────────────────
med_stock = {}
for r in snapshot:
    mid = r["medicine_id"]
    fac = fac_lookup.get(r["facility_id"], {})
    if mid not in med_stock:
        med_stock[mid] = {"facilities": [], "total": 0}
    med_stock[mid]["facilities"].append({
        "name":    fac.get("facility_name", r["facility_id"]),
        "district":fac.get("district", ""),
        "village": fac.get("village_town", ""),
        "type":    fac.get("facility_type", ""),
        "status":  r["stock_status"],
        "units":   int(float(r["quantity_on_hand"])),
    })
    if r["stock_status"] != "Out":
        med_stock[mid]["total"] += int(float(r["quantity_on_hand"]))

patient_medicines = []
for m in medicines_raw:
    mid = m["medicine_id"]
    si  = med_stock.get(mid, {"facilities": [], "total": 0})
    all_facs = [f for f in si["facilities"] if f["status"] != "Out"]
    patient_medicines.append({
        "id":         mid,
        "name":       m["medicine_name"],
        "category":   m["disease_category"],
        "dosage":     m["dosage_form"],
        "total":      si["total"],
        "facilities": all_facs[:8],
        "more_count": max(0, len(all_facs) - 8),
        "status":     "available" if si["total"] > 100 else ("low" if si["total"] > 0 else "out"),
    })

categories = sorted(set(m["disease_category"] for m in medicines_raw))
districts  = sorted(set(f["district"] for f in facilities_raw))

# ── Auth decorator ────────────────────────────────────────
def admin_required(f):
    @wraps(f)
    def dec(*a, **kw):
        if "admin_user" not in session:
            return redirect(url_for("admin_login"))
        return f(*a, **kw)
    return dec

