# ── AUTO-WRITE TEMPLATES ─────────────────────────────────
import base64 as _b64, os as _os
_T = {
    'admin_dashboard.html': '',
    'admin_login.html':     '',
    'patients.html':        '',
}
_TD = _os.path.join(_os.path.dirname(_os.path.abspath(__file__)),'templates')
