app = Flask(__name__)
app.secret_key = "sentinel-bw-2025"

# ── Routes ────────────────────────────────────────────────
@app.route("/")
def home():
    return redirect(url_for("admin_login"))

# Patient portal (public)
@app.route("/patient")
def patient_portal():
    return render_template("patients.html",
        categories=categories, districts=districts,
        medicines=patient_medicines)

@app.route("/patient/search")
def patient_search():
    q    = request.args.get("q", "").strip().lower()
    cat  = request.args.get("category", "").strip()
    dist = request.args.get("district", "").strip()
    results = list(patient_medicines)
    if q:
        results = [m for m in results if q in m["name"].lower() or q in m["category"].lower()]
    if cat and cat != "All Categories":
        results = [m for m in results if m["category"] == cat]
    if dist:
        filtered = []
        for m in results:
            facs = [f for f in m["facilities"] if f["district"] == dist]
            if facs:
                total_dist = sum(f["units"] for f in facs)
                mc = dict(m)
                mc["facilities"]  = facs[:8]
                mc["more_count"]  = max(0, len(facs) - 8)
                mc["total"]       = total_dist
                mc["status"]      = "available" if total_dist > 100 else ("low" if total_dist > 0 else "out")
                filtered.append(mc)
        results = filtered
    return render_template("patients.html",
        categories=categories, districts=districts,
        medicines=patient_medicines, results=results,
        query=request.args.get("q","").strip(),
        selected_category=cat, selected_district=dist)

@app.route("/api/suggest")
def suggest():
    q = request.args.get("q", "").strip().lower()
    if not q:
        return jsonify([])
    matches = [m for m in patient_medicines if q in m["name"].lower() or q in m["category"].lower()][:6]
    return jsonify([{"name":m["name"],"category":m["category"],"status":m["status"],"total":m["total"]} for m in matches])

# Admin auth
@app.route("/admin/login", methods=["GET","POST"])
def admin_login():
    if "admin_user" in session:
        return redirect(url_for("admin_dashboard"))
    error = None
    if request.method == "POST":
        u = request.form.get("username","").strip()
        p = request.form.get("password","")
        if u in ADMIN_USERS and ADMIN_USERS[u]["password"] == p:
            session["admin_user"] = u
            session["admin_name"] = ADMIN_USERS[u]["name"]
            session["admin_role"] = ADMIN_USERS[u]["role"]
            return redirect(url_for("admin_dashboard"))
        error = "Invalid username or password."
    return render_template("admin_login.html", error=error)

@app.route("/admin/logout")
def admin_logout():
    session.clear()
    return redirect(url_for("admin_login"))

@app.route("/admin")
@admin_required
def admin_dashboard():
    return render_template("admin_dashboard.html",
        stats=stats, alerts=alerts[:30],
        medicines=medicines_raw, facilities=facilities_raw,
        snapshot=snapshot, expiry=expiry_raw,
        stockout=stockout_7d, redist=redist_raw,
        district_risks=district_risks, disease_cases=disease_cases,
        symptoms=symptoms, med_lookup=med_lookup, fac_lookup=fac_lookup,
        admin_name=session.get("admin_name"),
        admin_role=session.get("admin_role"))

if __name__ == "__main__":
    app.run(debug=True)